from flask import Flask, request, jsonify, session
import os
from functools import wraps

app = Flask(__name__)
app.secret_key = 'your_secret_key'

# Dummy user database
users = {
    'user1': {'password': 'password123', 'mfa_enabled': True},
    'api_client': {'password': 'apipassword', 'mfa_enabled': False}
}

def check_credentials(username, password):
    if username in users and users[username]['password'] == password:
        return users[username]
    return None

def check_mfa(user):
    if user['mfa_enabled']:
        otp = request.form.get('otp')
        # For demonstration, assume OTP is '123456'
        if otp == '123456':
            session['logged_in'] = True
            return True
        else:
            return False
    else:
        session['logged_in'] = True
        return True

def require_login(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'logged_in' not in session or not session['logged_in']:
            return jsonify({'error': 'Unauthorized'}), 401
        return f(*args, **kwargs)
    return decorated_function

@app.route('/login', methods=['POST'])
def login():
    username = request.form.get('username')
    password = request.form.get('password')
    
    user = check_credentials(username, password)
    if not user:
        return jsonify({'error': 'Invalid credentials'}), 401
    
    if check_mfa(user):
        return jsonify({'message': 'Logged in successfully'})
    else:
        return jsonify({'error': 'MFA failed'}), 401

@app.route('/api/direct-login', methods=['POST'])
def direct_login():
    username = request.form.get('username')
    password = request.form.get('password')
    
    user = check_credentials(username, password)
    if not user:
        return jsonify({'error': 'Invalid credentials'}), 401
    
    # Assume API clients have mfa_enabled set to False
    session['logged_in'] = True
    return jsonify({'message': 'Logged in successfully'})

@app.route('/protected', methods=['GET'])
@require_login
def protected():
    return jsonify({'message': 'This is a protected route'})

if __name__ == '__main__':
    app.run(debug=True)